// Filter conversations that are due for a reminder based on timing
const items = $input.all();
const results = [];
const now = new Date();

for (const item of items) {
  const conv = item.json;
  if (!conv.id || !conv.whatsapp_chat_id) continue;

  const lastActivity = new Date(conv.updated_at || conv.created_at);
  const hoursSinceActivity = (now.getTime() - lastActivity.getTime()) / (1000 * 60 * 60);

  const remindersSent = conv.reminders_sent || 0;

  let shouldRemind = false;
  let reminderType = '';

  if (remindersSent === 0 && hoursSinceActivity >= 24) {
    shouldRemind = true;
    reminderType = '24h';
  } else if (remindersSent === 1 && hoursSinceActivity >= 72) {
    shouldRemind = true;
    reminderType = '72h';
  }

  if (shouldRemind) {
    results.push({
      json: {
        conversation_id: conv.id,
        contact_id: conv.contact_id,
        whatsapp_chat_id: conv.whatsapp_chat_id,
        qualification_step: conv.qualification_step || 1,
        reminders_sent: remindersSent,
        reminder_type: reminderType,
        collected_address: conv.collected_address,
        collected_wishes: conv.collected_wishes,
        collected_dimensions: conv.collected_dimensions,
        collected_email: conv.collected_email,
        collected_photos: conv.collected_photos
      }
    });
  }
}

return results.length > 0 ? results : [];

// Build context for Claude to generate a contextual reminder
const convData = $('Check Timing — Due for Reminder?').first().json;
const rawHistory = $input.first().json;

// Parse message history
let messages = [];
if (Array.isArray(rawHistory)) {
  messages = rawHistory;
} else if (Array.isArray(rawHistory.body)) {
  messages = rawHistory.body;
} else if (rawHistory.content) {
  messages = [rawHistory];
}

// Reverse to chronological order and format
const orderedHistory = [...messages].reverse();
const historyStr = orderedHistory.map((m, i) => {
  const dir = m.direction === 'outbound' ? 'BOT' : 'CUSTOMER';
  const content = m.type === 'image' ? '[Photo]' : m.content;
  return `${dir}: ${content}`;
}).join('\n');

const stepNames = {
  1: 'property address',
  2: 'garden wishes/project description',
  3: 'garden dimensions (LxW meters)',
  4: 'photos of the current situation',
  5: 'email address for the quote'
};

const nextStep = stepNames[convData.qualification_step] || 'property address';

const prompt = `CONVERSATION HISTORY:\n${historyStr || '(No messages yet)'}\n\nCONVERSATION STATUS:\nReminder type: ${convData.reminder_type} (${convData.reminder_type === '24h' ? 'first gentle nudge' : 'second follow-up, slightly more urgent'})\nNext info needed: ${nextStep}\nQualification step: ${convData.qualification_step}/5\nData collected so far: Address=${convData.collected_address || 'no'}, Wishes=${convData.collected_wishes || 'no'}, Dimensions=${convData.collected_dimensions || 'no'}, Email=${convData.collected_email || 'no'}`;

return [{
  json: {
    promptMessage: prompt,
    conversation_id: convData.conversation_id,
    contact_id: convData.contact_id,
    whatsapp_chat_id: convData.whatsapp_chat_id,
    reminders_sent: convData.reminders_sent,
    reminder_type: convData.reminder_type
  }
}];

// Extract the reminder text from Claude's response
const convData = $('Build AI Reminder Context').first().json;
const rawText = $input.first().json.content?.[0]?.text || $input.first().json.content || '';

// Clean up — remove any accidental markdown or extra whitespace
let reminderText = typeof rawText === 'string' ? rawText.trim() : String(rawText).trim();

// Fallback if empty
if (!reminderText) {
  reminderText = 'Hey! 👋 We merkten dat je nog niet hebt gereageerd. We helpen je graag verder met je tuinproject!';
}

return [{
  json: {
    reminder_text: reminderText,
    conversation_id: convData.conversation_id,
    contact_id: convData.contact_id,
    whatsapp_chat_id: convData.whatsapp_chat_id,
    reminders_sent: convData.reminders_sent,
    reminder_type: convData.reminder_type
  }
}];
